{"cmd":"bash -lc 'set -e
printf "== baseline metrics ==\n";
df -g / | awk "NR==2 { printf \"run_root_total_GB=%s\\nrun_root_avail_GB=%s\\n\", $2, $4 }";
df -g /System/Volumes/Data | awk "NR==2 { printf \"run_data_total_GB=%s\\nrun_data_avail_GB=%s\\n\", $2, $4 }";
printf "== sudo probe ==\n";
if sudo -n true 2>/dev/null; then echo "sudo_available=1"; else echo "sudo_available=0"; fi;
printf "== memory_pressure ==\n";
memory_pressure 2>/dev/null | head -n 8;
printf "== swap ==\n";
sysctl vm.swapusage 2>/dev/null || true;
printf "== top cpu >3.0%% ==\n";
ps -axo pid=,pcpu=,pmem=,command= | awk "$2+0>3.0 { print }" | head -n 20;
printf "== candidate user caches / logs sizes ==\n";
list_items=(
  "$HOME/Library/Caches/com.openai.codex"
