  "$HOME/Library/Application\ Support/Codex/Default/DawnGraphiteCache"
  "$HOME/Library/Application\ Support/Codex/Default/DawnWebGPUCache"
  "$HOME/Library/Application\ Support/Codex/Default/component_crx_cache"
  "$HOME/Library/Application\ Support/Codex/Default/extensions_crx_cache"
  "$HOME/Library/Logs/com.openai.codex"
  "$HOME/Library/Logs/Alpha"
  "$HOME/Library/Logs/SerenityDailyAnalysis"
  "$HOME/Library/Logs/OpenAIDatabase"
  "$HOME/Library/Logs/com.openai.sky.CUAService"
  "$HOME/Library/Logs/com.microsoft.VSCode"
);
for p in "${list_items[@]}"; do
  if [ -e "$p" ]; then du -sk "$p" | awk "{print \$1 \"KB\" \"\t\" \$2}"; else echo "0KB\t$p [missing]"; fi;
done;
printf "== tmp-like candidate paths ==\n";
for base in /tmp /private/tmp /var/tmp /private/var/tmp; do
  if [ -d "$base" ]; then
    printf "BASE:%s\n" "$base";
    find "$base" -maxdepth 1 -mindepth 1 \( -type f -o -type d \) \( -name "mac-*" -o -name "mac_cleanup*" -o -name "mac_48h*" -o -name "codex*" -o -name "eei*" -o -name "adp*" -o -name "playwright*" -o -name "node-compile-cache*" -o -name "pytest-of-linzezhang*" -o -name "F3CNN*" -o -name "moomoo*" -o -name "tmp*" -o -name "paragon-uc-cache*" \) -print | head -n 200;
  fi;
done;
printf "== /private/var/folders/T candidates ==\n";
if [ -d /private/var/folders ]; then
  for troot in $(find /private/var/folders -type d -path '*/T' 2>/dev/null | head -n 20); do
    echo "T:$troot";
    find "$troot" -maxdepth 1 -mindepth 1 \( -type d -o -type f \) \( -name "mac-*" -o -name "codex*" -o -name "playwright*" -o -name "F3CNN*" -o -name "moomoo*" -o -name "eei*" -o -name "adp*" -o -name "pytest-of-*" -o -name "tmp.*" -o -name "TelemetryUploadFile*" \) -print | head -n 80;
