  if [ -e "$d" ]; then echo "EXISTS $d"; else echo "MISSING $d"; fi;
done;
printf "== candidate helper processes ==\n";
for pname in spotlightknowledged.updater paragon-uc-cache watch_operator_soak.py chromium_headless_shell eei-ms-playwright; do
  pids=$(pgrep -f "$pname" || true);
  if [ -z "$pids" ]; then echo "$pname: no_match"; else printf "%s\n" "$pname"; for p in $pids; do ps -p "$p" -o pid=,pcpu=,pmem=,command=; done; fi;
done'"}

