payload.arguments:
{"cmd":"python3 -c 'import subprocess, re
cmd = ["bash","-lc","df -k /System/Volumes/Data | awk \"NR==2 {print \\\"pre_total\\\" $2 \\\" pre_free\\\" $4}\""]
out=subprocess.check_output(cmd).decode().strip()
parts=out.split()
# robust parse
def parse(label):
    for i,w in enumerate(parts):
        if w==label and i+1 < len(parts):
            return float(parts[i+1])
    return None
pre_total=float(parse("pre_total"))
pre_free=float(parse("pre_free"))
post=subprocess.check_output(["bash","-lc","df -k /System/Volumes/Data | awk \"NR==2 {print \"post_total\" $2 \" post_free\" $4}\""]).decode().strip().split()

def parse2(arr,label):
    for i,w in enumerate(arr):
        if w==label and i+1 < len(arr):
            return float(arr[i+1])
    return None
post_total=parse2(post,"post_total")
post_free=parse2(post,"post_free")
removed_kb=pre_free-post_free
print(f"run_before_total_gb={pre_total/1024/1024:.3f}")
print(f"run_before_free_gb={pre_free/1024/1024:.3f}")
print(f"run_after_free_gb={post_free/1024/1024:.3f}")
print(f"cleaned_gb={removed_kb/1024/1024:.3f}")
print(f"delta_gb={abs((post_free-pre_free))/1024/1024:.3f}")'"}
